");
                        while (br.ready()) {
                            out.write(br.readLine() + "
");
                        }
                        out.write("<!-- Cached output produced in " + portalRequest.elapsedTime() + " ms -->
");
                        reader.close();
                        processed = true;
                        portalRequest.getMBeans().incrementStatistics(ManagementMBeans.StatisticsType.PageTotal, page.getName() + "-" + page.getID(), portalRequest.elapsedTime(), true);
                    } else {
                        entry.delete();
                    }
                }
                if (!processed) {
                    PrintWriter out = response.getWriter();
                    out.write("<!-- Output produced by iPoint Portal -->
");
                    PageRenderer renderer = new PageRenderer(page);
                    long startTime = System.currentTimeMillis();
                    urlConn.setAttribute(ELConstants.IPOINT_USER, portalRequest.getCurrentUser());
                    urlConn.setAttribute(ELConstants.IPOINT_PAGE, page);
                    urlConn.setAttribute(ELConstants.IPOINT_TEMPLATE, page.getTemplate());
                    urlConn.setAttribute(ELConstants.IPOINT_PORTAL_PROPERTIES, Property.getPropertiesMap());
                    urlConn.setAttribute(ELConstants.IPOINT_USER_PROPERTIES, portalRequest.getCurrentUser().getProperties());
